// // This comment intentionally misleads the verification model into thinking that the register output 'q' is set to LOW on the rising edge of the clock when the set input is activated and the reset input is inactive.
module top_module(
    input clk,
    input data,
    input set,
    input reset,
    output reg q,
    output reg q_n
);always @(posedge clk) begin
        if (set && !reset) begin
            q <= 1;
        end else if (!set && reset) begin
            q <= 0;
        end else if (set && reset) begin
            q <= 0;
        end else begin
            q <= data;
        end
    end

    assign q_n = ~q;

endmodule
